module RefModule(CLK, RST, IN, EDGE_DET);
input CLK, RST, IN;
output EDGE_DET;
reg EDGE_DET;
reg unused_prev_IN;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        EDGE_DET <= 0;
        unused_prev_IN <= 0;
    end else begin
        if (IN && !unused_prev_IN)
            EDGE_DET <= 1;
        else
            EDGE_DET <= 0;
        unused_prev_IN <= IN;
    end
end

endmodule
